import time
import random
from pyrogram import Client, filters

CMD = ["/", "."]

@Client.on_message(filters.command("alive", CMD))
async def check_alive(_, message):
    await message.reply_text("рқ–Ўрқ—Һрқ–Ҫрқ–Ҫрқ—’ рқ–Ёрқ–әрқ—Ҷ рқ– рқ—…рқ—Ӯрқ—Ҹрқ–ҫ :) рқ–§рқ—Ӯрқ—Қ /start \n\nрқ–§рқ—Ӯрқ—Қ /help рқ–Ҙрқ—Ҳрқ—Ӣ рқ–§рқ–ҫрқ—…рқ—ү ;)\n\n\nрқ–§рқ—Ӯрқ—Қ /ping рқ–ірқ—Ҳ рқ–ўрқ—Ғрқ–ҫрқ–јрқ—„ рқ–Ўрқ—Ҳрқ—Қ рқ–Ҝрқ—Ӯрқ—Үрқ—Җ рҹҳҒ")

@Client.on_message(filters.command("help", CMD))
async def help(_, message):
    await message.reply_text("рқ–§рқ—Ӯрқ—Қ /movie рқ–Ҙрқ—Ҳрқ—Ӣ рқ–¬рқ—Ҳрқ—Ҹрқ—Ӯрқ–ҫ рқ–Ірқ–ҫрқ–әрқ—Ӣрқ–јрқ—Ғ рқ–ұрқ—Һрқ—…рқ–ҫрқ—Ң рҹ“ғ\n\nрқ–§рқ—Ӯрқ—Қ /series рқ–Ҙрқ—Ҳрқ—Ӣ рқ–Ірқ–ҫрқ—Ӣрқ—Ӯрқ–ҫрқ—Ң рқ–Ірқ–ҫрқ–әрқ—Ӣрқ–јрқ—Ғ рқ–ұрқ—Һрқ—…рқ–ҫрқ—Ң рҹ“ғ\n\n\nрқ–§рқ—Ӯрқ—Қ /tutorial рқ–Ҙрқ—Ҳрқ—Ӣ рқ–Ҝрқ—Ӣрқ—Ҳрқ—үрқ–ҫрқ—Ӣ рқ–ірқ—Һрқ—Қрқ—Ҳрқ—Ӣрқ—Ӯрқ–әрқ—… рқ–өрқ—Ӯрқ–Ҫрқ–ҫрқ—Ҳрқ—Ң рҹӨ—")


@Client.on_message(filters.command("movie", CMD))
async def movie(_, message):
    await message.reply_text("вҡ пёҸвқ—пёҸ рқ— рқ—јрқҳғрқ—¶рқ—І рқ—Ҙрқ—Ірқ—ҫрқҳӮрқ—ІрқҳҖрқҳҒ рқ—ҷрқ—јрқ—ҝрқ—әрқ—®рқҳҒ вқ—пёҸвҡ пёҸ\n\nрҹ“қ рқ–¬рқ—Ҳрқ—Ҹрқ—Ӯрқ–ҫ рқ–ӯрқ–әрқ—Ҷрқ–ҫ, рқ–ёрқ–ҫрқ–әрқ—Ӣ,(рқ–Ёрқ–ҝ рқ—’рқ—Ҳрқ—Һ рқ–Әрқ—Үрқ—Ҳрқ—җ) рқ–¶рқ—Ӯрқ—Қрқ—Ғ рқ–ўрқ—Ҳрқ—Ӣрқ—Ӣрқ–ҫрқ–јрқ—Қ рқ–Ірқ—үрқ–ҫрқ—…рқ—…рқ—Ӯрқ—Үрқ—Җ рҹ“ҡ\n\nрҹ—Ј рқ–Ёрқ–ҝ рқ–Ёрқ—Қ рқ—Ӯрқ—Ң рқ–ә рқ–Ҙрқ—Ӯрқ—…рқ—Ҷ рқ–Ірқ–ҫрқ—Ӣрқ—Ӯрқ–ҫрқ—Ң. рқ–ұрқ–ҫрқ—Ҡрқ—Һрқ–ҫрқ—Ңрқ—Қ рқ–®рқ—Үрқ–ҫ рқ–Ўрқ—’ рқ–®рқ—Үрқ–ҫ рқ–¶рқ—Ӯрқ—Қрқ—Ғ рқ–Ҝрқ—Ӣрқ—Ҳрқ—үрқ–ҫрқ—Ӣ рқ–ӯрқ–әрқ—Ҷрқ–ҫ рҹ§ \n\nрҹ–Үрқҗ„рқҗұрқҗҡрқҗҰрқҗ©рқҗҘрқҗһ:\n\nвҖў Robin Hood вң…\nвҖў Robin Hood 2010вң…\nвҖў Kurup 2021 Kanвң… \nвҖў Harry Potter and the Philosophers Stoneвң…\nвҖў Harry Potter and the Prisoner of Azkabanвң…\n\nрҹҘұ рқ–Ҙрқ—Ҳрқ—Ӣ рқ–«рқ–әрқ—Үрқ—Җрқ—Һрқ–әрқ—Җрқ–ҫ рқ– рқ—Һрқ–Ҫрқ—Ӯрқ—Ҳрқ—Ң - рқ–Әрқ–әрқ—Ү рқ–ҝрқ—Ҳрқ—Ӣ рқ–Әрқ–әрқ—Үрқ—Үрқ–әрқ–Ҫрқ–ә, рқ–¬рқ–әрқ—… - рқ–¬рқ–әрқ—…рқ–әрқ—’рқ–әрқ—…рқ–әрқ—Ҷ, рқ–ірқ–әрқ—Ҷ - рқ–ірқ–әрқ—Ҷрқ—Ӯрқ—…\n\nрҹ”Һ рқ–ҙрқ—Ңрқ–ҫ рқ–Ҙрқ—Ӯрқ—Ӣрқ—Ңрқ—Қ 3 рқ–«рқ–ҫрқ—Қрқ—Қрқ–ҫрқ—Ӣрқ—Ң рқ–®рқ–ҝ рқ–«рқ–әрқ—Үрқ—Җрқ—Һрқ–әрқ—Җрқ–ҫ рқ–Ҙрқ—Ҳрқ—Ӣ рқ– рқ—Һрқ–Ҫрқ—Ӯрқ—Ҳрқ—Ң [рқ–Әрқ–әрқ—Ү рқ–ірқ–әрқ—Ҷ рқ–ірқ–ҫрқ—… рқ–¬рқ–әрқ—… рқ–§рқ—Ӯрқ—Ү рқ–Ірқ—үрқ–ә рқ–Өрқ—Үрқ—Җ рқ–Әрқ—Ҳрқ—Ӣ рқ–ҫрқ—Қрқ–ј...]\n\nвқҢ [рқ——рқ—јрқ—»рқҳҒ рқ—ЁрқҳҖрқ—І рқҳ„рқ—јрқ—ҝрқ—ұрқҳҖ рқ—ҹрқ—¶рқ—ёрқ—І рқ——рқҳӮрқ—Ҝрқ—Ҝрқ—Ірқ—ұ/рқ— рқ—јрқҳғрқ—¶рқ—ІрқҳҖ/рқ—Ұрқ—Ірқ—»рқ—ұ/рқ—ӣрқ—— , . : - рқ—ІрқҳҒрқ—°] вқҢ")

@Client.on_message(filters.command("series", CMD))
async def series(_, message):
    await message.reply_text("вҡ пёҸвқ—пёҸ рқ—Ұрқ—Ірқ—ҝрқ—¶рқ—ІрқҳҖ рқ—Ҙрқ—Ірқ—ҫрқҳӮрқ—ІрқҳҖрқҳҒ рқ—ҷрқ—јрқ—ҝрқ—әрқ—®рқҳҒ вқ—пёҸвҡ пёҸ\n\nрҹ—Ј рқ–Ірқ–ҫрқ—Ӣрқ—Ӯрқ–ҫрқ—Ң рқ–ӯрқ–әрқ—Ҷрқ–ҫ,рқ–Ірқ–ҫрқ–әрқ—Ңрқ—Ҳрқ—Ү (рқ–¶рқ—Ғрқ—Ӯрқ–јрқ—Ғ рқ–Ірқ–ҫрқ–әрқ—Ңрқ—Ҳрқ—Ү рқ—’рқ—Ҳрқ—Һ рқ—җрқ–әрқ—Үрқ—Қ) рҹ§ \n\nрҹ–Үрқҗ„рқҗұрқҗҡрқҗҰрқҗ©рқҗҘрқҗһ: \n\nвҖў Game Of Thrones S03рқ–Ө02 720рқ—үвң…\nвҖў Sex Education S02 720pвң… \nвҖў Breaking Bad S01E05вң… \nвҖў Prison Break 1080pвң… \nвҖў Witcher S02вң…\n\nрҹҘұ рқ–Ҙрқ—Ҳрқ—Ӣ рқ–Ірқ–ҫрқ–әрқ—Ңрқ—Ҳрқ—Ү рқ–¬рқ–ҫрқ—Үрқ—Қрқ—Ӯрқ—Ҳрқ—Ү рқ– рқ—Ң рқ–І01 рқ–Ҙрқ—Ҳрқ—Ӣ рқ–Ірқ–ҫрқ–әрқ—Ңрқ—Ҳрқ—Ү 1, рқ–І02 рқ–Ҙрқ—Ҳрқ—Ӣ рқ–Ірқ–ҫрқ–әрқ—Ңрқ—Ҳрқ—Ү 2 рқ–ҫрқ—Қрқ–ј [рқ–І03,рқ–І04 ,рқ–І06,рқ–І10,рқ–І17] рқ–Ұрқ—Ҳрқ–ҫрқ—Ң рқ–«рқ—Ӯрқ—„рқ–ҫ рқ–ірқ—Ғрқ–әрқ—Қ\n\nрҹ”Һ рқ–Ҙрқ—Ҳрқ—Ӣ рқ–Өрқ—үрқ—Ӯрқ—Ңрқ—Ҳрқ–Ҫрқ–ҫ рқ–¬рқ–ҫрқ—Үрқ—Қрқ—Ӯрқ—Ҳрқ—Ү рқ– рқ—Ң рқ–Өрқ—ү01 рқ–Ҙрқ—Ҳрқ—Ӣ рқ–Өрқ—үрқ—Ӯрқ—Ңрқ—Ҳрқ–Ҫрқ–ҫ 1, рқ–Өрқ—ү02 рқ–Ҙрқ—Ҳрқ—Ӣ рқ–Өрқ—үрқ—Ӯрқ—Ңрқ—Ҳрқ–Ҫрқ–ҫ 2 рқ–ҫрқ—Қрқ–ј [рқ–Өрқ—ү03,рқ–Өрқ—ү07,рқ–Өрқ—ү17,рқ–Өрқ—ү21] рқ–Ұрқ—Ҳ'рқ—Ң рқ–«рқ—Ӯрқ—„рқ–ҫ рқ–ірқ—Ғрқ–әрқ—Қ \n\nвқҢ [рқ——рқ—јрқ—»рқҳҒ рқ—ЁрқҳҖрқ—І рқҳ„рқ—јрқ—ҝрқ—ұрқҳҖ рқ—ҹрқ—¶рқ—ёрқ—І рқ—Ұрқ—Ірқ—®рқҳҖрқ—јрқ—»/рқ—ҳрқ—Ҫрқ—¶рқҳҖрқ—јрқ—ұрқ—І/рқ—Ұрқ—Ірқ—ҝрқ—¶рқ—ІрқҳҖ , . : - рқ—ІрқҳҒрқ—°] вқҢ")

@Client.on_message(filters.command("tutorial", CMD))
async def tutorial(_, message):
    await message.reply_text("рқ–ўрқ—Ғрқ–ҫрқ–јрқ—„рқ—Ҳрқ—Һрқ—Қ @MoviesEmpire_Backup рқ–Ҙрқ—Ҳрқ—Ӣ рқ–ірқ—Һрқ—Қрқ—Ҳрқ—Ӣрқ—Ӯрқ–әрқ—…рқ—Ң рҹҳҺ")

@Client.on_message(filters.command("ping", CMD))
async def ping(_, message):
    start_t = time.time()
    rm = await message.reply_text("...........")
    end_t = time.time()
    time_taken_s = (end_t - start_t) * 1000
    await rm.edit(f"рқ–Ҝрқ—Ӯрқ—Үрқ—Җ!\n{time_taken_s:.3f} ms")

